    std::uint64_t aNonceWordF = TwistMix64::DiffuseA(pNonce * 0xE94BC77FB1DDB7BFULL + 0xA0D18B709A4A3290ULL);
    std::uint64_t aNonceWordG = TwistMix64::DiffuseC(pNonce * 0xACB1FDABC85A4D4BULL + 0xFE1D6FCFF8D45A56ULL);
    std::uint64_t aNonceWordH = TwistMix64::DiffuseB(pNonce * 0xCCD8595139FF4F0DULL + 0xB1C3EEBC81C5F11FULL);
    std::uint64_t aNonceWordI = TwistMix64::DiffuseC(pNonce * 0xAF55B35E8B66D10FULL + 0xBBE704F50EB09620ULL);
    std::uint64_t aNonceWordJ = TwistMix64::DiffuseB(pNonce * 0xA63950452D23B97BULL + 0xF7A054A38F86582AULL);
