    std::uint64_t aNonceWordM = TwistMix64::DiffuseC(pNonce * 0xE46E0775526237C1ULL + 0xCCC4529DF715A11DULL);
    std::uint64_t aNonceWordN = TwistMix64::DiffuseB(pNonce * 0x86D627A1B6C7090BULL + 0xC4C985A4ABFCB412ULL);
