            aCross = RotL64(pSnow[((S_BLOCK1 - aIndex + 4779U)) & S_BLOCK1], 37U) ^ RotL64(aSource[((S_BLOCK1 - aIndex + 3868U)) & S_BLOCK1], 53U);
