            //
            aOrbiterA = (((aWandererI + RotL64(aIngress, 38U)) + RotL64(aCarry, 29U)) + 16462052553719977502U) + aOrbiterAssignSaltB[(((31U - aIndex) + 14U)) & S_SALT1];
            aOrbiterB = (aWandererG + RotL64(aPrevious, 51U)) + 12337064059566619581U;
