            aOrbiterJ = (aOrbiterJ + aOrbiterA) + 11150566414723818350U;
            aOrbiterF = (aOrbiterF ^ aOrbiterJ) ^ 8336366151003049546U;
            aOrbiterF = RotL64((aOrbiterF * 9033771197242493699U), 11U);
            //
            aOrbiterB = ((aOrbiterB + aOrbiterI) + 13233968794237090787U) + aOrbiterUpdateSaltF[((aIndex + 29U)) & S_SALT1];
            aOrbiterC = (aOrbiterC ^ aOrbiterB) ^ 8172558473508478819U;
            aOrbiterC = RotL64((aOrbiterC * 17837070423649268435U), 29U);
            //
            aOrbiterI = (aOrbiterI + aOrbiterF) + 133564480283347997U;
            aOrbiterG = (aOrbiterG ^ aOrbiterI) ^ 15104810248883567064U;
            aOrbiterG = RotL64((aOrbiterG * 706802420642303533U), 35U);
            //
            aOrbiterE = (((aOrbiterE + aOrbiterK) + 9138629520201127075U) + aOrbiterUpdateSaltB[(((31U - aIndex) + 26U)) & S_SALT1]) + aNonceWordD;
            aOrbiterB = (aOrbiterB ^ aOrbiterE) ^ 13993086066341664080U;
            aOrbiterB = RotL64((aOrbiterB * 4875046427147105077U), 47U);
            //
            aOrbiterC = (aOrbiterC + aOrbiterG) + 6547273508580516932U;
            aOrbiterK = (aOrbiterK ^ aOrbiterC) ^ 9838727018769865759U;
            aOrbiterK = RotL64((aOrbiterK * 11395273371936839815U), 43U);
            //
            aOrbiterG = (aOrbiterG + aOrbiterD) + 11685694999526122626U;
            aOrbiterJ = (aOrbiterJ ^ aOrbiterG) ^ 8945983172566303116U;
            aOrbiterJ = RotL64((aOrbiterJ * 17791527981004597623U), 37U);
            //
            aOrbiterH = (aOrbiterH + aOrbiterC) + 17606249889617356327U;
            aOrbiterE = (aOrbiterE ^ aOrbiterH) ^ 9296903152000480008U;
            aOrbiterE = RotL64((aOrbiterE * 18066622289408024413U), 53U);
            //
            aOrbiterF = (aOrbiterF + aOrbiterH) + 14248192861977167583U;
            aOrbiterD = (aOrbiterD ^ aOrbiterF) ^ 5467843420970464193U;
            aOrbiterD = RotL64((aOrbiterD * 10121398470914323221U), 57U);
            //
            aOrbiterK = (aOrbiterK + aOrbiterJ) + 17072313558131700643U;
