            //
            aOrbiterD = ((aOrbiterD + aOrbiterE) + 15377107166135929052U) + aOrbiterUpdateSaltC[(((31U - aIndex) + 17U)) & S_SALT1];
            aOrbiterA = (aOrbiterA ^ aOrbiterD) ^ 16462052553719977502U;
            aOrbiterA = RotL64((aOrbiterA * 9057188521274832217U), 41U);
            //
            aIngress = RotL64(aOrbiterE, 43U) ^ aOrbiterD;
            aIngress = aIngress + (RotL64(aOrbiterJ, 39U) ^ aOrbiterI);
            aIngress = aIngress + (aOrbiterG ^ RotL64(aOrbiterB, 37U));
            aIngress = aIngress + (aOrbiterF ^ RotL64(aOrbiterA, 41U));
            aIngress = aIngress + (aOrbiterC ^ RotL64(aOrbiterK, 23U));
            aIngress = aIngress + RotL64(aOrbiterH, 34U);
            aIngress = TwistMix64::DiffuseC((aIngress + aScatter));
            //
            aWandererC = aWandererC + (((RotL64(aScatter, 30U) + RotL64(aOrbiterK, 43U)) + aOrbiterE) + RotL64(aCarry, 43U));
            aWandererK = aWandererK ^ (((RotL64(aCross, 57U) + aOrbiterE) + RotL64(aOrbiterF, 58U)) + aWandererUpdateSaltA[((aIndex + 13U)) & S_SALT1]);
            aWandererI = aWandererI + ((RotL64(aIngress, 35U) + aOrbiterI) + RotL64(aOrbiterF, 21U));
            aWandererJ = aWandererJ ^ ((RotL64(aPrevious, 41U) + aOrbiterC) + RotL64(aOrbiterE, 47U));
